class Solution {
    public int minSwaps(String s) {
        int n = s.length();
        int open = n / 2, close = n / 2;
        int swaps = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '[') {
                if (open > 0) {
                    open--;
                } else {
                    swaps++;
                }
            } else {
                if (close > 0) {
                    close--;
                } else {
                    swaps++;
                }
            }
        }
        return swaps;
    }
}
```

